import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Update to Reporting on Cost/Spend Data","description":"","frontmatter":{"title":"Update to Reporting on Cost/Spend Data","slug":"update-to-reporting-on-costspend-data"},"headers":[],"relativePath":"account-hub/update-to-reporting-on-costspend-data.md","filePath":"account-hub/update-to-reporting-on-costspend-data.md"}'),i={name:"account-hub/update-to-reporting-on-costspend-data.md"};function s(r,e,d,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[n('<p>Reporting on cost/spend data is important for measuring performance. We have launched two improvements aimed at making cost data reporting more intuitive and understandable 💲</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Improvements have been made to Ads Analytics related to cost/spend data. Previously, for cases where ad networks have multiple disparate media structure types, Branch pulled the Cost/Click/Impression data separately, and that data cannot be combined in reporting. This led to a misalignment of the totals shown in metric columns.</p><h3 id="data-selection-and-defaults" tabindex="-1">Data Selection and Defaults <a class="header-anchor" href="#data-selection-and-defaults" aria-label="Permalink to &quot;Data Selection and Defaults&quot;">​</a></h3><p>In cases where there are multiple data sources for Cost/Click/Impression data from an ad network, Branch will select the appropriate data source for the report based on which dimensions are added. Branch will intelligently select a &quot;default&quot; data source if there is a conflict or clash between dimensions. This results in a more consistent experience when generating reports.</p><h3 id="new-ui-components" tabindex="-1">New UI Components <a class="header-anchor" href="#new-ui-components" aria-label="Permalink to &quot;New UI Components&quot;">​</a></h3><p>During report creation in the <a href="./paid-ads-analytics.html">Events Table</a> and when dimensions have been selected from one data source, Branch dynamically adds new icon tooltips that will indicate a warning about incompatible dimensions.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ready to learn more about your ads analytics? Visit our guide on Ads Analytics here: <a href="./paid-ads-analytics.html">Ads Analytics</a></p></div><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h4 id="which-dimensions-are-compatible-with-which-ad-networks" tabindex="-1">Which dimensions are compatible with which Ad Networks? <a class="header-anchor" href="#which-dimensions-are-compatible-with-which-ad-networks" aria-label="Permalink to &quot;Which dimensions are compatible with which Ad Networks?&quot;">​</a></h4><p>A helpful table has been created to show which dimensions are compatible with which ad networks <a href="./paid-ads-analytics.html#dimension-compatibility-for-cost-aggregation">here</a>.</p><h4 id="what-happens-if-dimensions-across-two-data-sources-are-added-to-a-report" tabindex="-1">What happens if dimensions across two data sources are added to a report? <a class="header-anchor" href="#what-happens-if-dimensions-across-two-data-sources-are-added-to-a-report" aria-label="Permalink to &quot;What happens if dimensions across two data sources are added to a report?&quot;">​</a></h4><p>To preserve logical totals, Branch will only ever use one data source at a time. Dimensions from the unused data source will have Cost/Click/Impression values of 0.</p><h4 id="is-this-a-common-occurrence" tabindex="-1">Is this a common occurrence? <a class="header-anchor" href="#is-this-a-common-occurrence" aria-label="Permalink to &quot;Is this a common occurrence?&quot;">​</a></h4><p>Ad networks offering incompatible dimensions are the exception, not the rule. Examples:</p><ul><li>Apple Ads - <code>Keyword</code> vs <code>Display Ad</code></li><li>Facebook/Meta - <code>Secondary Publisher</code> vs <code>Geo</code></li></ul>',16)])])}const u=a(i,[["render",s]]);export{m as __pageData,u as default};
